// n8n Code node (JavaScript)
// Input: items desde "Get many rows" (Baserow)
// Output: items con { text, payload, metadata } limpios para RAG

function val(x) {
  // Select/multiselect de Baserow: queremos .value
  if (x && typeof x === 'object' && 'value' in x) return x.value;
  return x ?? '';
}

function arrValues(arr) {
  if (!Array.isArray(arr)) return [];
  return arr.map(v => val(v)).filter(Boolean);
}

function num(x) {
  if (x == null) return null;
  const n = Number(String(x).replace(/[, ]+/g, ''));
  return Number.isFinite(n) ? n : null;
}

function int(x) {
  if (x == null) return null;
  const n = parseInt(String(x), 10);
  return Number.isFinite(n) ? n : null;
}

const out = items.map(item => {
  const r = item.json || {};

  const serviceId = r.ServiceId;
  const slug = r.Slug;
  const name = r.Name;

  // Campos de texto que sí embebemos
  const description      = r.Description || '';
  const keyFeatures      = r.KeyFeatures || '';
  const useCases         = r.UseCases || '';
  const differentiators  = r.Differentiators || '';
  const audience         = r.Audience || '';

  // Texto canónico para embeddings (lo que irá al splitter)
  const parts = [];
  if (description)     parts.push(description);
  if (keyFeatures)     parts.push(`Features: ${keyFeatures}`);
  if (useCases)        parts.push(`Use cases: ${useCases}`);
  if (differentiators) parts.push(`Differentiators: ${differentiators}`);
  if (audience)        parts.push(`Audience: ${audience}`);
  const text = parts.join('\n\n');

  // Payload limpio (solo lo útil para filtros/UX)
  const payload = {
    service_id:    serviceId,
    slug:          slug,
    name:          name,
    category:      val(r.Category),
    pricing_model: val(r.PricingModel),
    starting_price: num(r.StartingPrice),
    sla_tier:      val(r.SLA_Tier),
    audience:      audience || '',
    status:        val(r.Status),
    languages:     arrValues(r.Languages),
    integrations:  arrValues(r.Integrations),
    tags:          arrValues(r.Tags),
    public_url:    r.PublicURL || '',
    owner:         r.Owner || '',
    updated_at:    r.UpdatedAt || '',
    schema_v:      int(r.SchemaV),
    source:        'baserow.Services',
  };

  // Sugerencia para id estable por chunk (lo construirá el Vector Store)
  // Aquí solo pasamos el "baseId" para que lo uses como prefijo si hace falta.
  const baseId = serviceId;

  return {
    json: {
      // Campo que usará el Default Data Loader / Token Splitter
      text,
      // Metadatos para Qdrant (puedes mapearlo como "payload" o "metadata")
      payload,
      metadata: payload,
      // Útil si quieres construir el id final `${service_id}:${chunk_idx}`
      baseId,
    },
  };
});

return out;
